import React, { useEffect, useMemo, useState, useCallback } from 'react';
import {
  Alert,
  Button,
  Platform,
  SafeAreaView,
  StyleSheet,
  Text,
  TextInput,
  View,
  ActivityIndicator,
} from 'react-native';
import AsyncStorage from '@react-native-async-storage/async-storage';
import ReactNativeBiometrics from 'react-native-biometrics';

const AUTH_FLAG_KEY = 'auth:isAuthenticated';
const DEMO_PASSWORD = 'password123';

const rnBiometrics = new ReactNativeBiometrics();

async function getBiometricAvailability() {
  try {
    const { available, biometryType } = await rnBiometrics.isSensorAvailable();
    return { available: !!available, biometryType: biometryType || null };
  } catch {
    return { available: false, biometryType: null };
  }
}

async function setAuthenticated(value) {
  await AsyncStorage.setItem(AUTH_FLAG_KEY, value ? '1' : '0');
}

async function getAuthenticated() {
  const v = await AsyncStorage.getItem(AUTH_FLAG_KEY);
  return v === '1';
}

async function clearAuthenticated() {
  await AsyncStorage.removeItem(AUTH_FLAG_KEY);
}

function getBiometricLabel(biometryType) {
  if (biometryType === ReactNativeBiometrics.FaceID) return 'Face ID';
  if (biometryType === ReactNativeBiometrics.TouchID) return 'Touch ID';
  if (biometryType === ReactNativeBiometrics.Biometrics) return 'Biometrics';
  return 'Biometrics';
}

export default function App() {
  const [booting, setBooting] = useState(true);
  const [isAuthed, setIsAuthed] = useState(false);
  const [bioAvailable, setBioAvailable] = useState(false);
  const [bioType, setBioType] = useState(null);

  const [password, setPassword] = useState('');
  const [busy, setBusy] = useState(false);

  const bioLabel = useMemo(() => getBiometricLabel(bioType), [bioType]);

  const refreshAuthState = useCallback(async () => {
    const [authed, bio] = await Promise.all([getAuthenticated(), getBiometricAvailability()]);
    setIsAuthed(authed);
    setBioAvailable(bio.available);
    setBioType(bio.biometryType);
  }, []);

  useEffect(() => {
    let mounted = true;
    (async () => {
      try {
        await refreshAuthState();
      } finally {
        if (mounted) setBooting(false);
      }
    })();
    return () => {
      mounted = false;
    };
  }, [refreshAuthState]);

  const handleBiometricLogin = useCallback(async () => {
    setBusy(true);
    try {
      const { available, biometryType } = await getBiometricAvailability();
      setBioAvailable(available);
      setBioType(biometryType);

      if (!available) {
        Alert.alert('Biometrics unavailable', 'Use password to continue.');
        return;
      }

      const promptMessage =
        Platform.OS === 'ios'
          ? `Authenticate with ${getBiometricLabel(biometryType)}`
          : 'Authenticate to continue';

      const { success } = await rnBiometrics.simplePrompt({
        promptMessage,
        cancelButtonText: 'Cancel',
      });

      if (success) {
        await setAuthenticated(true);
        setIsAuthed(true);
      } else {
        Alert.alert('Authentication cancelled', 'Use password to continue.');
      }
    } catch (e) {
      Alert.alert('Authentication failed', e?.message ? String(e.message) : 'Please try again or use password.');
    } finally {
      setBusy(false);
    }
  }, []);

  const handlePasswordLogin = useCallback(async () => {
    setBusy(true);
    try {
      if (!password || password.length < 1) {
        Alert.alert('Missing password', 'Enter your password.');
        return;
      }
      if (password !== DEMO_PASSWORD) {
        Alert.alert('Invalid password', 'Try again.');
        return;
      }
      await setAuthenticated(true);
      setIsAuthed(true);
      setPassword('');
    } finally {
      setBusy(false);
    }
  }, [password]);

  const handleLogout = useCallback(async () => {
    setBusy(true);
    try {
      await clearAuthenticated();
      setIsAuthed(false);
      setPassword('');
      await refreshAuthState();
    } finally {
      setBusy(false);
    }
  }, [refreshAuthState]);

  if (booting) {
    return (
      <SafeAreaView style={styles.center}>
        <ActivityIndicator />
        <Text style={styles.muted}>Loading…</Text>
      </SafeAreaView>
    );
  }

  if (isAuthed) {
    return (
      <SafeAreaView style={styles.container}>
        <View style={styles.card}>
          <Text style={styles.title}>Home</Text>
          <Text style={styles.subtitle}>You are authenticated.</Text>
          <View style={styles.spacer} />
          <Button title={busy ? 'Please wait…' : 'Logout'} onPress={handleLogout} disabled={busy} />
        </View>
      </SafeAreaView>
    );
  }

  return (
    <SafeAreaView style={styles.container}>
      <View style={styles.card}>
        <Text style={styles.title}>Login</Text>
        <Text style={styles.subtitle}>
          {bioAvailable
            ? `Use ${bioLabel} or password.`
            : 'Biometrics not available on this device. Use password.'}
        </Text>

        <View style={styles.spacer} />

        {bioAvailable ? (
          <View style={styles.row}>
            <View style={styles.flex}>
              <Button
                title={busy ? 'Please wait…' : `Login with ${bioLabel}`}
                onPress={handleBiometricLogin}
                disabled={busy}
              />
            </View>
          </View>
        ) : null}

        <View style={styles.spacer} />

        <Text style={styles.label}>Password</Text>
        <TextInput
          value={password}
          onChangeText={setPassword}
          placeholder="Enter password"
          secureTextEntry
          autoCapitalize="none"
          autoCorrect={false}
          editable={!busy}
          style={styles.input}
          returnKeyType="done"
          onSubmitEditing={handlePasswordLogin}
        />

        <View style={styles.spacer} />
        <Button title={busy ? 'Please wait…' : 'Login with password'} onPress={handlePasswordLogin} disabled={busy} />

        <View style={styles.spacer} />
        <Text style={styles.hint}>Demo password: {DEMO_PASSWORD}</Text>
      </View>
    </SafeAreaView>
  );
}

